previewCss:
.darma-loader-darma-custom-253 {
  color: var(--loader-color, #ca8a04);
  display: inline-grid;
}
.darma-loader-darma-custom-253:before,
.darma-loader-darma-custom-253:after {
  content: "";
  grid-area: 1/1;
  height: 28px;
  aspect-ratio: 5;
  --c: currentColor 90deg,#0000 0;
  background:
   conic-gradient(from 135deg at top   ,var(--c)),
   conic-gradient(from -45deg at bottom,var(--c)) 12.5% 100%;
  background-size: 20% 50%;
  background-repeat: repeat-x;
  -webkit-mask: repeating-linear-gradient(90deg,currentColor 0 10%,#0000 0 20%);
  clip-path: inset(0 100% 0 0);
  animation: darma-loader-darma-custom-253-l14 1.5s infinite steps(6,jump-none);
}
.darma-loader-darma-custom-253:after {
  scale: -1 1;
}
@keyframes darma-loader-darma-custom-253-l14{
  to {clip-path: inset(0)}
}

